"use strict";(self.webpackChunkwebpage=self.webpackChunkwebpage||[]).push([[189],{4189:p=>{p.exports=JSON.parse('{"menu":{"company":"О компании","team":"Наша команда","rule":"Правила бесплатного пользования","contact":"Связаться с нами","home":"Главная"},"test":"Тестовый","s1-title1":"Бесплатное — отнюдь не самое дорогое","s1-title2":"Мы торжественно заявляем: никаких коммерческих уловок!","s1-title3":"Пусть в мире не будет \\"горячих картофелин\\", а у простых людей будут удобные инструменты","s1-title4":"IoT для всего — передача решений","company":{"name":"Guangzhou Zhichang Qier Juanjin Internet Technology Co., Ltd.","address":"Гуанчжоу, район Хуанпу, ул. Чжуншань Авеню Ист, 280-1, бизнес-центр Huaying, офис 303","description":"Здравствуйте, меня зовут Тан Линь, я разработчик, которого \\"выбросили\\" с рынка труда. Именно я инициировал создание компании Guangzhou Zhichang Qier Juanjin Internet Technology Co., Ltd. Это молодая компания, полная энергии и решимости. Наши сотрудники — это опытные ИТ-специалисты старшего возраста, также оказавшиеся ненужными рынку, со средним стажем работы 5 лет. Все они мои бывшие коллеги и друзья, столкнувшиеся с такой же дискриминацией. Мысль о создании собственной компании зрела давно, и это стало неизбежным результатом. Возможно, я подошел к названию несколько вольно; раньше думал о вариантах вроде \\"Частная кастомизация\\", но они не передавали мою историю. Текущее название прямо говорит о моем статусе и целях на данном этапе. Выбранная модель работы стала возможной благодаря современным трендам интернета. Мы — трудолюбивая команда, любящая исследования, и мы хотим делиться их результатами, бесплатно предоставляя различные инструменты и сервисы. Мы готовы исследовать передовые технологии и брать на себя риски инноваций вместо вас. Я сделаю всё возможное, чтобы поддержать каждого предпринимателя, осмелившегося мечтать. Наша компания может бесплатно разработать для вас коммерческие системы ERP, CMS, OA, мини-приложения, мобильные приложения и 2D-игры. Мы работаем в сфере ПО для ПК и мобильных устройств, а также с передовыми технологиями: IoT, AI, OCR, VR/AR, RVC, WRTC и др. В будущем мы планируем объединить софт и оборудование. Надеемся, что наши продукты вам понравятся так же сильно, как нам нравится создавать качественные инструменты для разных отраслей."},"rule":{"contents":"Содержание страницы","p1":{"title":"Вступление","p11":"Открытость — все инструменты следуют лицензии GPL","p12":"Свобода — это не возможность делать всё что угодно, а возможность выбирать не делать того, чего не хочешь","p13":"Справедливость — не ведем недобросовестную конкуренцию, не создаем монополий","p14":"Публичность — прозрачные финансы, честный сервис без мелкого шрифта и игр со словами","p15":"Всеми силами поддерживаем каждого мечтателя-предпринимателя~"},"p2":{"title":"Разоблачение инсайдов индустрии","p21":"Здесь мы описываем правила и будем дополнять их при необходимости. Также разоблачаем типичные ловушки \\"бесплатных\\" коммерческих предложений:","p22":{"p221":"<strong>Использование бесплатности для \\"стрижки\\" пользователей</strong>: в продукте либо бесконечная реклама, либо платные доп. инструменты. Пример — крупные игры: скачать можно бесплатно, но для комфортной игры придется постоянно покупать предметы. Итог: <strong>\\"бесплатное — самое дорогое\\"</strong>.","p222":{"p2221":"<strong>Бесплатность как прикрытие для иных целей.</strong> Истинная цель — сбор данных пользователей, продвижение платных услуг или агрессивный маркетинг.","p2222":"По сути, бесплатный пробный период с последующим платным продлением (это относительно нормально).","p2223":"Мошенничество: бесплатный продукт не соответствует рекламируемому, но связан с ним (часто встречается в инфобизнесе).","p2224":"Обмен: бесплатность в обмен на долю рынка (недобросовестные компании используют ваши данные). В индустрии это называют \\"цзюань\\" (внутренняя конкуренция).","p2225":"Вредоносное ПО: под видом бесплатного софта предлагаются патчи или кряки со скриптами для кражи данных."},"p223":"Реклама-липучка: когда рассказывают только о выгодной части бизнеса. Продукт бесплатен, но для его работы нужны платные компоненты. Например: открытый код бесплатен, но документация платная."}},"p3":{"title":"Почему мы работаем бесплатно?","p31":"Нам тоже нужно место на рынке. Такую конкуренцию мы называем \\"восходящей\\" (shangjuan). В отличие от \\"нисходящей\\", основанной на демпинге и эксплуатации, наша строится на инновациях, создании рабочих мест и техническом прогрессе. Можно сказать, мы готовим революцию.","p32":"По сути, мы — ваши технологические акционеры. Наша цель — дать предпринимателям инструменты для успеха.","p33":"Ценность ИТ-инструментов размыта. Слишком дорого — вы аутсорсер, слишком дешево — торговец софтом. В текущей экономике рынок не готов платить даже себестоимость разработки. Ценность инструмента проявляется только через продукт.","p34":"Максимальное сокращение расходов компаний на техперсонал, искоренение неэффективного использования кадров.","p35":"Объединение опытных специалистов, невостребованных рынком, и создание новой экосистемы фриланса, подходящей современным условиям.","p36":"Максимальная отдача ценности каждого индивида обществу.","p37":"Стремление к оптимальному решению: мы подбираем формат работы под ваш бюджет и прибыльность, избегая \\"фастфуд-проектов\\" ради долгосрочного качества."},"p4":{"title":"Модель работы","p41":"Работа строится по трем типам отношений:","p42":{"title":"Три типа отношений","p421":{"title":"I. Партнерство","p4211":"Сотрудничество ради общей выгоды. Мы бесплатно предоставляем труд для создания вашего продукта. Мы получаем долю только когда проект приносит доход. В команду входят менеджеры, дизайнеры, тестировщики и разработчики. Есть два варианта:","p4212":{"title":"Вариант 1: До покрытия затрат","p42121":"Мы забираем себестоимость труда x2. Себестоимость считается по <a1>первой ступени</a1> найма. Устанавливается коридор сумм и процент отчислений. Мы не вмешиваемся в управление. При отсутствии дохода выплаты не производятся. После выплаты суммы (завершения контракта) новые функции оплачиваются по <a2>второй ступени</a2>, поддержка — по <a3>третьей</a3>. При досрочном прекращении не по естественным причинам клиент не получает права на продукт."},"p4213":{"title":"Вариант 2: До истечения срока","p42131":"Фиксированные ежемесячные выплаты на основе \\"вклада проекта\\" до конца срока контракта. При досрочном разрыве взимается ликвидационная стоимость. Права на продукт принадлежат клиенту только при естественном завершении контракта."},"p4214":"В период работы по этим моделям мы не берем плату за обслуживание. Бесплатно до конца!","p4215":"Если вы уверены в успехе проекта на 80%, выбирайте вариант 2. Если вы стартап в поиске инвестиций — вариант 1.","p4216":"Если критически важно владеть ресурсами сразу или защитить данные, выбирайте вариант 2 с коротким сроком или модель найма."},"p422":{"title":"II. Совладение","p4221":"Если проект перспективен, мы можем войти в него как технологические соучредители. Это самый глубокий уровень бесплатной поддержки для инновационных проектов."},"p423":{"title":"III. Наем","p4231":"Почасовая работа (удаленно). Стандарт — 8 рабочих часов в день. Цены зависят от опыта специалиста и делятся на три ступени:","p4232":"Первая ступень: Реальная стоимость специалиста (в среднем 60-75 CNY/ч).","p4233":"Вторая ступень: Скидка 15% от первой ступени.","p4234":"Третья ступень: Скидка 75% от первой ступени.","p4235":"Примечание: В партнерстве мы делим риски с вами. Модель партнерства для нас приоритетнее. Право окончательного толкования остается за командой.","p4236":"Не путайте это с обычным аутсорсингом. Разница в подходе к управлению ресурсами и гибкости (<a1>калькулятор цен</a1>)."}}},"p5":{"title":"Часто задаваемые вопросы","p51":"Как вы узнаете о доходах моего проекта?","p52":"Если данные и операции проходят через нас, мы видим оценку. Проверка финотчетов обычно не требуется. Если команда бросает проект, ресурсы остаются у нас.","p53":"Как гарантируется честность?","p54":"Обе стороны участвуют в оценке. Мы сами предоставляем серверы и оборудование бесплатно, а после завершения контракта передаем все доступы вам.","p55":"Что такое \\"вклад проекта\\"?","p56":"Это процентное значение: Доход от данного проекта / Общий доход компании * 100%. Вы сами оцениваете этот вклад.","p57":"Что если проект будет заброшен на полпути?","p58":"При одностороннем отказе Заказчика выплачивается компенсация за объем выполненных работ по модели найма.","p59":"По другим вопросам свяжитесь с нами, мы ответим оперативно!"},"p6":{"title":"Заключение","p61":"Это чистая помощь без участия в капитале (на этапе развития). Мы получаем отдачу только от реального дохода. Если проект прогорит — мы не получим ничего. Это подходит для стартапов с ограниченным бюджетом. После запуска есть два пути:","p62":"До покрытия затрат (гибкая рассрочка)","p63":"Процент от дохода. Ставка — честные 0.25% в месяц (ниже любого банка, без сложных схем). Формула: Ставка часа x Срок x Процент x 2. До полной выплаты нельзя менять юрлицо или владельца.","p64":"До истечения срока (фиксированная рассрочка)","p65":"Оценка стоимости продукта распределяется на период 2-5 лет. Выплаты производятся фиксированно, пока проект живет, независимо от прибыли.","p66":"Если мы видим, что проект заведомо провальный, мы за него не возьмемся. Нам важно глубокое погружение в проект.","p67":"Главное — создать продукт и начать действовать. Проблемы будем решать по мере поступления."}},"cal":{"title":"Калькулятор цен","p1":"Видимый интерфейс (UI)","p2":"Общее количество страниц","p21":"Невидимый функционал","p22":"Логика бэкенда или фронтенда, не отраженная в UI (например, разработка SDK).","p23":"Нужно ли тестирование","p24":"Выберите, если хотите минимизировать количество багов.","p25":"Нужна ли интеграция","p26":"Не выбирайте, если бэкенд не требуется или не нуждается в стыковке.","p27":"Количество архитектур","p28":"Фундамент проекта. Если используется готовый фреймворк без доработок — не выбирать. Разные нативные платформы считаются как разные архитектуры. Кроссплатформенность — как одна.","p29":"Количество человек","p210":"Сколько специалистов задействовано (минимум 1).","p211":"Способ оплаты","p212":"Выберите вариант","p213":"Размер скидки при рассрочке. Оплата тремя частями: при подписании, по завершении разработки и после приемки.","p214":"Оценка срока (дни)","p215":"дней","p216":"Результат расчета:","p217":"Рассчитать","hint1":"Введите количество","hint2":"Результат ориентировочный, точные данные — в контракте!","resutlHint":"Прим.: Время в часах (h), цена в юанях (CNY), \\"?\\" — нехватка данных, \\"-\\" — только логика без UI, \\"x\\" — бэкенд не требуется."}}')}}]);